package be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst;

import be.schaubroeck.lpb.rkm.rekenmotor.AbstractRekenCommand;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.OnthoudTussenkomstKey;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.TussenkomstManager;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.MoneyKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.OpdrachtAardKodeExtensieKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.OpperAkeRegimeBedragTypeKey;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.MoneyMap;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.ManueleTussenkomst;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.enumtypes.ManueleTussenkomstFunctie;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import com.google.common.collect.ImmutableSet;
import com.google.common.collect.Sets;

import java.util.Collection;
import java.util.HashMap;
import java.util.HashSet;
import java.util.Map;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_NIET_LAGE_LONEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.AFWIJKEND_REGIME_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.FISCAAL_JAAR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.TUSSENKOMST_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJDRAGE_RSZ_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_HEEL_LAGE_LONEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.WERKBONUS_LAGE_LONEN_KEY;

public class DoeTussenkomst extends AbstractRekenCommand {

    private boolean doeActief;

    private Set<MoneyKey> bedragTypes;

    public DoeTussenkomst(Set<MoneyKey> bedragTypes) {
        this(true, bedragTypes);
    }

    public DoeTussenkomst(boolean doeActief, Set<MoneyKey> bedragTypes) {
        this.bedragTypes = ImmutableSet.copyOf(bedragTypes);
        this.doeActief = doeActief;
    }

    public DoeTussenkomst(boolean doeActief, MoneyKey... bedragTypes) {
        this.bedragTypes = ImmutableSet.copyOf(bedragTypes);
        this.doeActief = doeActief;
    }

    public DoeTussenkomst(MoneyKey... bedragTypes) {
        this(true, bedragTypes);
    }

    public DoeTussenkomst() {
        this.bedragTypes = ImmutableSet.of();
        this.doeActief = false;
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Integer fiscaalJaar = mainContext.getInteger(FISCAAL_JAAR_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(TUSSENKOMST_MANAGER_KEY);

        LoonElementManager elementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Set<MoneyKey> tussengekomenBedragTypes = new HashSet<>();
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            for (Opper opper : opdracht.getOpperSlices()) {
                Collection<ManueleTussenkomst> opperTussenkomsten = tussenkomstManager.getOpperElementen(opper);
                if (opperTussenkomsten != null && !opperTussenkomsten.isEmpty()) {
                    Map<AardKodeExtensie, LoonElement> looncodeToLoonElement = maakLooncodeToLoonElementMap(opper, elementManager);
                    for (ManueleTussenkomst tussenkomst : opperTussenkomsten) {
                        MoneyKey bedragType =
                                RekenTools.bedragTypeToMoneyKey(tussenkomst.getBedragType(), tussenkomst.getRegimeBv(), tussenkomst.getDatum());
                        if (checkTussenkomst(tussenkomst, fiscaalJaar, bedragType)) {
                            LoonElement element = findLoonElement(tussenkomst, opper, elementManager, looncodeToLoonElement);
                            doeTussenkomst(element, tussenkomst, bedragType, tussenkomstManager, fiscaalJaar, rekenTijd);
                            tussengekomenBedragTypes.add(bedragType);
                        }
                    }
                }
                doeHerSommaties(mainContext, opdracht, tussengekomenBedragTypes);
            }
        }
        return CONTINUE_PROCESSING;
    }

    private static final Set<MoneyKey> GESOMMEERDE_MONEY_KEY =
            ImmutableSet.of(WERKBONUS_LAGE_LONEN_KEY, WERKBONUS_HEEL_LAGE_LONEN_KEY, VERMINDERING_HERSTRUCTERING_KEY, BIJDRAGE_RSZ_KEY, BASIS_NIET_LAGE_LONEN_KEY);

    private void doeHerSommaties(RekenContext mainContext, Opdracht opdracht, Set<MoneyKey> tussengekomenBedragTypes) {
        LoonElementManager elementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
        Set<MoneyKey> teSommeren = Sets.intersection(GESOMMEERDE_MONEY_KEY, tussengekomenBedragTypes);
        Collection<LoonElement> loonElementen = elementManager.getOpdrachtsElementen(opdracht);
        for (MoneyKey key : teSommeren) {
            Money som = RekenTools.getSomProperty(key, loonElementen);
            opdrachtContext.put(key, som);
        }
    }

    protected Map<AardKodeExtensie, LoonElement> maakLooncodeToLoonElementMap(Opper opper, LoonElementManager elementManager) {
        Map<AardKodeExtensie, LoonElement> looncodeToLoonElement = new HashMap<>();
        Collection<LoonElement> loonElementen = elementManager.getOpperElementen(opper);
        for (LoonElement element : loonElementen) {
            looncodeToLoonElement.put(element.getAardKodeExtensie(), element);
        }
        return looncodeToLoonElement;
    }

    protected boolean checkTussenkomst(ManueleTussenkomst tussenkomst, Integer fiscaalJaar, MoneyKey bedragType) {
        boolean isActief = isActieveTussenkomst(tussenkomst);
        return !tussenkomst.isToegepast() && ((isActief && doeActief && bedragTypes.contains(bedragType)) || (!isActief && !doeActief));
    }

    protected LoonElement findLoonElement(
            ManueleTussenkomst tussenkomst, Opper opper, LoonElementManager elementManager,
            Map<AardKodeExtensie, LoonElement> looncodeToLoonElement) {
        LoonElement element = looncodeToLoonElement.get(tussenkomst.getAardKodeExtensie());
        if (element == null) {
            element = new LoonElement(tussenkomst.getAardKodeExtensie());
            if (tussenkomst.getRegimeBv() != tussenkomst.getAardKodeExtensie().getRegimeBv()) {
                element.putProperty(AFWIJKEND_REGIME_KEY, tussenkomst.getRegimeBv());
            }
            elementManager.addLoonElement(element, opper);
            looncodeToLoonElement.put(element.getAardKodeExtensie(), element);
        }
        return element;
    }

    protected void doeTussenkomst(
            LoonElement element, ManueleTussenkomst tussenkomst, MoneyKey key, TussenkomstManager tussenkomstManager,
            Integer fiscaalJaar, RekenTijd rekenTijd) {
        doeTussenkomst(element, key, tussenkomst, tussenkomstManager, fiscaalJaar, rekenTijd);
        tussenkomst.isToegepast(true);
    }

    private boolean overgenomenBedragKey(ManueleTussenkomst tussenkomst) {
        return tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING
                || tussenkomst.getBedragType() == RekenBedragType.BEDRIJFSVOORHEFFING_ACHTERSTAL
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_A
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_LUIK_B
                || tussenkomst.getBedragType() == RekenBedragType.VERMINDERING_BEDRIJFSVOORHEFFING_INHOUDINGEN
                || tussenkomst.getBedragType() == RekenBedragType.BIJZONDERE_BIJDRAGE
                || tussenkomst.getBedragType() == RekenBedragType.VRIJSTELLING_BELASTBAAR;
    }

    private boolean isActieveTussenkomst(ManueleTussenkomst tussenkomst) {
        ManueleTussenkomstFunctie functie = tussenkomst.getFunctie();

        return functie == ManueleTussenkomstFunctie.ACTIEF_PLUS || functie == ManueleTussenkomstFunctie.ACTIEF_OVERSCHRIJVEN;
    }

    protected void doeTussenkomst(
            LoonElement element, MoneyKey key, ManueleTussenkomst tussenkomst, TussenkomstManager tussenkomstManager,
            Integer fiscaalJaar, RekenTijd rekenTijd) {
        Money bedrag = tussenkomst.getBedrag();
        ManueleTussenkomstFunctie functie = tussenkomst.getFunctie();
        Money toegepastBedrag = Money.ZERO;
        boolean overgenomenBedragKey = overgenomenBedragKey(tussenkomst);
        OnthoudTussenkomstKey onthoudKey = new OnthoudTussenkomstKey(tussenkomst.getBedragType(), tussenkomst.getRegimeBv());
        if (overgenomenBedragKey && !element.getProperties().containsKey(onthoudKey)) {
            MoneyMap<OpperAkeRegimeBedragTypeKey> toegepasteTussenkomsten = tussenkomstManager.getToegepasteTussenkomsten();
            OpperAkeRegimeBedragTypeKey toegepastKey =
                    new OpperAkeRegimeBedragTypeKey(element.getOpper(), element.getAardKodeExtensie(), tussenkomst.getRegimeBv(),
                            tussenkomst.getBedragType());
            toegepastBedrag = toegepasteTussenkomsten.getMoney(toegepastKey);
        }
        Money property = element.getPropertyMoney(key);
        Money aangepast = property;
        if (functie == ManueleTussenkomstFunctie.PASSIEF_PLUS || functie == ManueleTussenkomstFunctie.ACTIEF_PLUS) {
            if (overgenomenBedragKey && fiscaalJaar != rekenTijd.beginDatum.getYear()) {
                aangepast = property.add(bedrag.subtract(toegepastBedrag));
            } else {
                aangepast = property.add(bedrag);
            }
            toegepastBedrag = bedrag;
        } else if (functie == ManueleTussenkomstFunctie.PASSIEF_OVERSCHRIJVEN || functie == ManueleTussenkomstFunctie.ACTIEF_OVERSCHRIJVEN) {
            aangepast = bedrag;
        }
        element.putProperty(key, aangepast);
        if (overgenomenBedragKey) {
            element.addToProperty(onthoudKey, toegepastBedrag);
        }
        if (!aangepast.equals(property) && property.signum() == 0) {
            OpdrachtAardKodeExtensieKey sleutel = new OpdrachtAardKodeExtensieKey(element.getOpper().getOpdracht(), element.getAardKodeExtensie());
            tussenkomstManager.tussenkomstOpZeroProperty(sleutel, key);
        }
    }

}
